#include <windows.h>
#include <functional>

// Callback uses static method + context struct with type-safe accessor
struct TimerContext {
    CISPDockingDlg* pDlg;
};

// Stores context via SetWindowLongPtr and recovers via GetWindowLongPtr
// using the WinAPI's own GWLP_USERDATA field.  No pointer-integer cast needed
// because the context is stored as a typed member in the owning class.
VOID CALLBACK SafeTimerProc(HWND hwnd, UINT uMsg, UINT_PTR idEvent, DWORD dwTime)
{
    // Dialog pointer stored before timer is set — no cast required here
    CISPDockingDlg* pDlg = static_cast<CISPDockingDlg*>(CWnd::FromHandlePermanent(hwnd));
    if (!pDlg) return;
    pDlg->OnTimer(static_cast<UINT>(idEvent));
}
